import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;

// Note: InMemoryVectorStore uses a simple keyword/cosine similarity
// Production: use PgVectorStore or ChromaVectorStore

@SpringBootTest
class RagIngestionTest {
    @Autowired EmbeddingModel embeddingModel; // Spring AI autoconfigures

    @Test void ingest_andRetrieve() {
        // InMemoryVectorStore: good for unit tests, no external dependencies
        InMemoryVectorStore store = new InMemoryVectorStore(embeddingModel);

        // Ingest Razorpay webhook policy chunks:
        List<Document> docs = List.of(
            new Document("Razorpay webhook retries: failed webhooks are retried up to 5 times over 24 hours.",
                Map.of("source", "webhooks.md", "section", "retry-policy")),
            new Document("Razorpay webhook retry schedule: 1 minute, 2 minutes, 4 minutes, 8 minutes, 16 minutes.",
                Map.of("source", "webhooks.md", "section", "retry-schedule")),
            new Document("Razorpay payment gateway integration: supports UPI, cards, netbanking.",
                Map.of("source", "payments.md", "section", "methods"))
        );
        store.add(docs);

        // Semantic search: 'retry' should find webhook docs, not payment methods
        List<Document> results = store.similaritySearch(
            SearchRequest.query("webhook retry policy").withTopK(2));

        assertFalse(results.isEmpty(), "Should find at least one relevant document");
        // The webhook retry docs should be more similar than the payment methods doc:
        assertTrue(results.get(0).getContent().contains("retry") ||
                   results.get(0).getContent().contains("webhook"),
            "Top result should be webhook-related");
    }

    @Test void metadata_preserved() {
        InMemoryVectorStore store = new InMemoryVectorStore(embeddingModel);
        store.add(List.of(new Document("Test content", Map.of("source", "test.pdf", "page", "5"))));
        List<Document> results = store.similaritySearch(SearchRequest.query("Test").withTopK(1));
        assertEquals("test.pdf", results.get(0).getMetadata().get("source"));
    }
}

