// # pgvector: PostgreSQL extension, no separate vector DB needed!
// # Same DB your Spring Boot app already uses

// Spring configuration:
import org.springframework.context.annotation.*;
import org.springframework.boot.test.context.SpringBootTest;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Configuration
class PgVectorConfig {
    // PgVectorStore is autoconfigured by Spring AI when:
    // 1. spring-ai-pgvector-store-spring-boot-starter is on classpath
    // 2. application.yml has spring.ai.vectorstore.pgvector.* properties
    // 3. DataSource is configured (standard Spring datasource)
    //
    // PgVectorStore bean is created automatically — just inject VectorStore!
    //
    // WHY pgvector vs InMemoryVectorStore:
    // InMemoryVectorStore:
    //   + Simple, no dependencies
    //   + Good for tests
    //   - Lost on restart
    //   - Single pod only (no sharing between instances)
    //   - No persistence (re-ingest on every startup)
    //
    // PgVectorStore:
    //   + Persistent (survives restarts)
    //   + Shared between all pods (one DB, multiple app instances)
    //   + HNSW index: approximate nearest neighbor (fast at scale)
    //   + Transactional: vector ops in same PostgreSQL transaction as business data
    //   + Same DB: no new infrastructure if already using Postgres
    //   + Backup: included in regular Postgres backup
    //
    // HNSW vs IVFFlat index:
    //   HNSW: better recall, faster queries, recommended for most cases
    //   IVFFlat: lower memory, slower build, good for huge datasets (100M+)
}

@SpringBootTest
class PgVectorDocTest {
    @Test void pgvector_conceptDocumented() {
        // pgvector = PostgreSQL + vector operations
        // SELECT * FROM documents ORDER BY embedding <=> query_vector LIMIT 3;
        // <=>: cosine distance operator (Spring AI generates this automatically)
        System.out.println("pgvector: same PostgreSQL, vector search extension. No new infra!");
        assertTrue(true);
    }
}

import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;

@Service
class PolicyTextChunker {
    // Split text into overlapping chunks, respecting sentence boundaries:
    public List<String> chunk(String text, int maxCharsPerChunk, int overlapChars) {
        List<String> chunks = new ArrayList<>();
        if (text == null || text.isBlank()) return chunks;

        // Split by sentences (naive: split on '. '):
        String[] sentences = text.split("(?<=\\. )|(?<=\\!\\s)|(?<=\\?\\s)");
        StringBuilder current = new StringBuilder();

        for (String sentence : sentences) {
            if (current.length() + sentence.length() > maxCharsPerChunk && !current.isEmpty()) {
                chunks.add(current.toString().trim());
                // Overlap: take last 'overlapChars' from current chunk:
                String tail = current.toString();
                current = new StringBuilder(
                    tail.length() > overlapChars ? tail.substring(tail.length() - overlapChars) : tail);
            }
            current.append(sentence);
        }
        if (!current.isEmpty()) chunks.add(current.toString().trim());
        return chunks;
    }

    public int estimateTokens(String text) {
        return text.split("\\s+").length; // rough: 1 token ≈ 1 word (actually ~0.75 words)
    }
}

@SpringBootTest
class TextChunkerTest {
    @Autowired PolicyTextChunker chunker;

    @Test void shortText_singleChunk() {
        List<String> chunks = chunker.chunk("Hello. World.", 500, 50);
        assertEquals(1, chunks.size());
    }
    @Test void longText_multipleChunks() {
        String longText = "HDFC Bank home loans require minimum CIBIL score of 700. ".repeat(20);
        List<String> chunks = chunker.chunk(longText, 200, 30);
        assertTrue(chunks.size() > 1, "Long text should produce multiple chunks");
    }
    @Test void overlap_present_inChunks() {
        // Build text that forces chunking:
        String text = "First sentence here. Second sentence here. Third sentence here. Fourth sentence here.";
        List<String> chunks = chunker.chunk(text, 50, 20);
        if (chunks.size() > 1) {
            // Second chunk should contain overlap from first:
            String firstEnd = chunks.get(0).substring(Math.max(0, chunks.get(0).length() - 20));
            // The overlap content should appear in the second chunk's beginning:
            assertTrue(chunks.get(1).length() > 0); // at minimum: second chunk exists
        }
    }
}

