import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.util.stream.Collectors;

record RagTestCase(String question, String expectedSource) {}
record EvaluationResult(int total, int hits, double accuracy) {}

@Service
class RagEvaluator {
    private final VectorStore vectorStore;
    RagEvaluator(VectorStore vs) { vectorStore = vs; }

    public EvaluationResult evaluate(List<RagTestCase> testCases) {
        int hits = 0;
        for (RagTestCase tc : testCases) {
            List<Document> results = vectorStore.similaritySearch(
                SearchRequest.query(tc.question()).withTopK(3));
            boolean hit = results.stream()
                .anyMatch(d -> tc.expectedSource().equals(d.getMetadata().get("source")));
            if (hit) hits++;
        }
        double accuracy = testCases.isEmpty() ? 0 : (double) hits / testCases.size() * 100;
        return new EvaluationResult(testCases.size(), hits, accuracy);
    }
}

@SpringBootTest
class RagEvaluationTest {
    @Autowired EmbeddingModel embeddingModel;

    @Test void perfectRetrieval_100percent() {
        InMemoryVectorStore store = new InMemoryVectorStore(embeddingModel);
        store.add(List.of(
            new Document("Razorpay webhook retries 5 times.", Map.of("source", "webhooks.md")),
            new Document("Razorpay refund timeline: 5-7 business days.", Map.of("source", "refunds.md"))
        ));
        RagEvaluator evaluator = new RagEvaluator(store);
        List<RagTestCase> cases = List.of(
            new RagTestCase("How many times are webhooks retried?", "webhooks.md"),
            new RagTestCase("How long does refund take?", "refunds.md")
        );
        EvaluationResult result = evaluator.evaluate(cases);
        assertEquals(2, result.total());
        assertTrue(result.accuracy() >= 50.0, "At least 50% accuracy expected"); // flexible for embedding variance
    }
    @Test void wrongDocs_zeroHits() {
        InMemoryVectorStore store = new InMemoryVectorStore(embeddingModel);
        store.add(List.of(
            new Document("Totally unrelated: weather forecast.", Map.of("source", "weather.md"))
        ));
        RagEvaluator evaluator = new RagEvaluator(store);
        List<RagTestCase> cases = List.of(
            new RagTestCase("webhook retry policy", "webhooks.md") // webhooks.md not in store
        );
        EvaluationResult result = evaluator.evaluate(cases);
        assertEquals(0, result.hits()); // webhooks.md never retrieved (doesn't exist)
    }
}

