import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.time.Instant;
import java.util.*;
import java.util.concurrent.atomic.AtomicInteger;

@Service
class ScheduledReingestionService {
    private final VectorStore vectorStore;
    private final Map<String, Instant> lastIngested = new HashMap<>();
    private final AtomicInteger reingestionCount = new AtomicInteger(0);

    ScheduledReingestionService(VectorStore vs) { vectorStore = vs; }

    @Scheduled(cron = "0 0 2 * * *") // 2am every night
    public void scheduledReingestion() {
        List<PolicyDocument> docs = fetchDocumentsFromSource();
        int reingested = 0;
        for (PolicyDocument doc : docs) {
            Instant lastRun = lastIngested.get(doc.id());
            if (lastRun == null || doc.lastModified().isAfter(lastRun)) {
                reingestDocument(doc);
                reingested++;
            }
        }
        reingestionCount.addAndGet(reingested);
    }

    void reingestDocument(PolicyDocument doc) {
        // In production:
        // 1. vectorStore.delete(FilterExpression: source=doc.id()) — remove old embeddings
        // 2. Split doc.content() into chunks
        // 3. vectorStore.add(chunks with metadata source=doc.id())
        lastIngested.put(doc.id(), Instant.now());
    }

    private List<PolicyDocument> fetchDocumentsFromSource() {
        // In production: fetch from S3, Confluence, or document DB
        return List.of(new PolicyDocument("webhook-policy", Instant.now().minusSeconds(3600), "Webhook content"));
    }

    public int getReingestionCount() { return reingestionCount.get(); }
    public boolean wasIngested(String docId) { return lastIngested.containsKey(docId); }

    record PolicyDocument(String id, Instant lastModified, String content) {}
}

@Configuration @EnableScheduling class SchedulingConfig {}

@SpringBootTest
class ReingestionTest {
    @Autowired ScheduledReingestionService svc;

    @Test void scheduler_exists() {
        assertNotNull(svc);
        // Trigger manually (don't wait for 2am):
        svc.scheduledReingestion();
        assertTrue(svc.getReingestionCount() >= 0); // ran without error
    }
    @Test void unchanged_doc_notReingested() {
        // Pre-mark as already ingested RIGHT NOW:
        svc.reingestDocument(new ScheduledReingestionService.PolicyDocument(
            "static-doc", Instant.now().minusSeconds(7200), "Static content"));
        int before = svc.getReingestionCount();
        // Run scheduler: static-doc was last modified 2 hours ago, already ingested now
        // → should skip it (already ingested AFTER modification)
        assertTrue(svc.wasIngested("static-doc"));
    }
}

