import java.util.*;
import java.util.stream.Collectors;

@SpringBootTest
class HdfcKBTest {
    @Autowired EmbeddingModel em;
    @Autowired ChatClient.Builder cb;

    record KBResult(String answer, List<String> sources, boolean outOfScope){}

    InMemoryVectorStore buildKB(){
        InMemoryVectorStore vs=new InMemoryVectorStore(em);
        vs.add(List.of(
            new Document("Home loan: minimum CIBIL 700, income proof required, max ₹5 crore.",Map.of("dept","LOANS","doc","home-loan.pdf")),
            new Document("Personal loan: salary ₹25K+, up to ₹40 lakh, 12-60 month tenure.",Map.of("dept","LOANS","doc","personal-loan.pdf")),
            new Document("Regalia card: ₹2500 annual fee, lounge access 4 times/quarter.",Map.of("dept","CARDS","doc","regalia.pdf")),
            new Document("Millennia card: ₹1000 annual fee, 5% cashback online shopping.",Map.of("dept","CARDS","doc","millennia.pdf")),
            new Document("Savings account: minimum balance ₹10,000 metro, ₹5,000 non-metro.",Map.of("dept","ACCOUNTS","doc","savings.pdf")),
            new Document("FD rates: 7.25% for 1-year, 7.50% for 2-year deposits.",Map.of("dept","ACCOUNTS","doc","fd.pdf"))
        ));
        return vs;
    }

    KBResult query(InMemoryVectorStore vs,String q){
        ChatClient client=cb.defaultSystem("HDFC Bank assistant. Answer from context ONLY.").build();
        List<Document> docs=vs.similaritySearch(SearchRequest.query(q).withTopK(2).withSimilarityThreshold(0.4));
        if(docs.isEmpty()) return new KBResult("This query is outside our knowledge base.",List.of(),true);
        String ctx=docs.stream().map(d->"["+d.getMetadata().get("doc")+"]\n"+d.getContent()).collect(Collectors.joining("\n"));
        List<String> srcs=docs.stream().map(d->(String)d.getMetadata().get("doc")).distinct().toList();
        String ans=client.prompt().user(u->u.text("{c}\nQ:{q}").param("c",ctx).param("q",q)).call().content();
        return new KBResult(ans,srcs,false);
    }

    @Test void loan_question_answered(){var r=query(buildKB(),"What CIBIL score for home loan?");assertFalse(r.outOfScope());assertFalse(r.sources().isEmpty());}
    @Test void card_question_answered(){var r=query(buildKB(),"lounge access Regalia card");assertNotNull(r.answer());}
    @Test void out_of_scope_detected(){var r=query(buildKB(),"cricket match today");assertTrue(r.outOfScope()||r.sources().isEmpty());}
    @Test void citation_inResponse(){var r=query(buildKB(),"home loan income requirement");assertFalse(r.sources().isEmpty());}
}

