import org.springframework.ai.vectorstore.*;
import org.springframework.ai.document.Document;
import org.springframework.ai.embedding.EmbeddingModel;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.util.stream.Collectors;

@Service
class HybridSearchService {
    private final List<Document> allDocs = new ArrayList<>(); // for keyword search
    private InMemoryVectorStore semanticStore;

    void addDocuments(InMemoryVectorStore vs, List<Document> docs) {
        semanticStore = vs; allDocs.addAll(docs);
    }

    // Keyword search: exact case-insensitive match:
    List<Document> keywordSearch(String query) {
        String lower = query.toLowerCase();
        return allDocs.stream()
            .filter(d -> d.getContent().toLowerCase().contains(lower))
            .collect(Collectors.toList());
    }

    // Semantic search:
    List<Document> semanticSearch(String query) {
        return semanticStore == null ? List.of() :
            semanticStore.similaritySearch(SearchRequest.query(query).withTopK(3));
    }

    // Hybrid: merge keyword + semantic, deduplicate by content:
    List<Document> hybridSearch(String query) {
        Set<String> seen = new LinkedHashSet<>();
        List<Document> results = new ArrayList<>();

        // Keyword results first (exact match = higher precision):
        keywordSearch(query).forEach(d -> {
            if (seen.add(d.getContent())) results.add(d);
        });

        // Then semantic results (may find synonyms/paraphrases):
        semanticSearch(query).forEach(d -> {
            if (seen.add(d.getContent())) results.add(d);
        });

        return results.stream().limit(5).collect(Collectors.toList());
    }
}

@SpringBootTest
class HybridSearchTest {
    @Autowired EmbeddingModel em;

    HybridSearchService buildService() {
        InMemoryVectorStore vs = new InMemoryVectorStore(em);
        List<Document> docs = List.of(
            new Document("CIBIL score requirement: minimum 700 for home loan approval.", Map.of("source","loans.pdf")),
            new Document("Credit score must be above 700 to qualify for mortgage.", Map.of("source","mortgage.pdf")),
            new Document("Razorpay webhook retry: 5 attempts over 24 hours.", Map.of("source","webhooks.pdf"))
        );
        vs.add(docs);
        HybridSearchService svc = new HybridSearchService();
        svc.addDocuments(vs, docs);
        return svc;
    }

    @Test void keywordSearch_exactMatch() {
        var results = buildService().keywordSearch("CIBIL");
        assertTrue(results.stream().anyMatch(d -> d.getContent().contains("CIBIL")));
    }
    @Test void semanticSearch_synonymMatch() {
        var results = buildService().semanticSearch("credit score for house purchase");
        assertFalse(results.isEmpty()); // finds 'credit score' and 'home loan' semantically
    }
    @Test void hybridSearch_findsMore() {
        var keyword = buildService().keywordSearch("CIBIL");
        var hybrid = buildService().hybridSearch("CIBIL credit score");
        assertTrue(hybrid.size() >= keyword.size()); // hybrid >= keyword alone
    }
}

import org.springframework.ai.chat.client.ChatClient;
import org.springframework.ai.vectorstore.*;
import org.springframework.ai.document.Document;
import org.springframework.ai.embedding.EmbeddingModel;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.util.stream.Collectors;

record SynthRagResult(String answer,List<String> citations,boolean grounded){}

@SpringBootTest
class M26T2SynthesisTest {
    @Autowired EmbeddingModel em;
    @Autowired ChatClient.Builder cb;

    InMemoryVectorStore buildStore(){
        InMemoryVectorStore vs=new InMemoryVectorStore(em);
        vs.add(List.of(
            new Document("HDFC home loan minimum CIBIL: 700. Max amount ₹5 crore.",Map.of("src","home-loan.pdf","dept","LOANS")),
            new Document("HDFC personal loan: salary ₹25K required, max 60 months.",Map.of("src","personal.pdf","dept","LOANS")),
            new Document("HDFC Regalia card: 4 lounge visits, 2x rewards.",Map.of("src","regalia.pdf","dept","CARDS")),
            new Document("HDFC savings account minimum balance: ₹10,000 metro.",Map.of("src","savings.pdf","dept","ACCOUNTS"))
        ));
        return vs;
    }

    SynthRagResult query(InMemoryVectorStore vs,String q){
        ChatClient client=cb.defaultSystem("HDFC assistant. Answer from context ONLY. If not in context: 'Not in knowledge base.'").build();
        List<Document> docs=vs.similaritySearch(SearchRequest.query(q).withTopK(2).withSimilarityThreshold(0.4));
        if(docs.isEmpty()) return new SynthRagResult("Not in knowledge base.",List.of(),false);
        String ctx=docs.stream().map(d->"["+d.getMetadata().get("src")+"] "+d.getContent()).collect(Collectors.joining("\n"));
        List<String> cit=docs.stream().map(d->(String)d.getMetadata().get("src")).distinct().toList();
        String ans=client.prompt().user(u->u.text("{c}\nQ:{q}").param("c",ctx).param("q",q)).call().content();
        return new SynthRagResult(ans,cit,true);
    }

    int evaluateHitRate(InMemoryVectorStore vs,Map<String,String> qa){
        int hits=0;
        for(var e:qa.entrySet()){
            List<Document> docs=vs.similaritySearch(SearchRequest.query(e.getKey()).withTopK(3));
            if(docs.stream().anyMatch(d->e.getValue().equals(d.getMetadata().get("src")))) hits++;
        }
        return hits;
    }

    @Test void retrieval_findsRelevant(){var vs=buildStore();SynthRagResult r=query(vs,"CIBIL score home loan");assertFalse(r.citations().isEmpty());}
    @Test void citation_present(){var vs=buildStore();SynthRagResult r=query(vs,"lounge Regalia");assertTrue(r.grounded());assertFalse(r.citations().isEmpty());}
    @Test void outOfScope_notGrounded(){var vs=buildStore();SynthRagResult r=query(vs,"best Bollywood movie 2026");assertTrue(r.citations().isEmpty());}
    @Test void evaluation_hitRate(){
        var vs=buildStore();
        Map<String,String> qa=Map.of("home loan CIBIL","home-loan.pdf","lounge access","regalia.pdf");
        int hits=evaluateHitRate(vs,qa);
        assertTrue(hits>=0&&hits<=qa.size());
    }
}
